INSERT INTO `user` (`id`, `username`, `account`, `password`, `email`, `gender`, `age`, `birthday`, `avatar`, `status`, `create_time`, `update_time`) VALUES (34, '周彦', 'zhouyan', '$2a$10$MciG8RiZAf24gjTUsy8Vd.7S2Sc/OwN5SVk.liwpp5LlLqhvm01iW', '3348098119@qq.com', 1, 33, '1993-01-08', NULL, 1, '2026-03-07 02:46:05', '2026-03-07 02:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (11, 'Java面向对象编程深入理解', '## 面向对象编程的核心概念\n\n面向对象编程（OOP）是Java语言的核心思想，它主要包含三大特性：封装、继承和多态。\n\n### 封装\n\n封装是指将数据（属性）和操作数据的方法绑定在一起，对外隐藏内部实现细节。通过private关键字修饰成员变量，并提供public的getter/setter方法来控制访问。\n\n```java\npublic class User {\n    private String name;\n    private int age;\n\n    public String getName() {\n        return name;\n    }\n\n    public void setName(String name) {\n        this.name = name;\n    }\n}\n```\n\n封装的好处在于保护数据不被外部随意修改，同时降低了模块之间的耦合度，使得代码更易于维护和重构。\n\n### 继承\n\n继承是子类继承父类属性和方法的机制。Java中使用extends关键字实现继承关系。通过继承，我们可以复用已有的代码，建立类之间的层次结构。\n\n例如，我们可以定义一个Animal基类，然后让Dog和Cat类继承它，共享name和age等公共属性，同时各自实现不同的makeSound方法。\n\n### 多态\n\n多态是指同一个行为具有多个不同表现形式或形态的能力。在Java中，多态主要通过方法重写（Override）和方法重载（Overload）来实现。\n\n编译时多态通过方法重载实现，运行时多态通过方法重写和动态绑定实现。这是面向对象编程中最强大的特性之一。\n\n### 实践建议\n\n在实际开发中，应该优先使用组合而非继承，遵循"组合优于继承"的设计原则。同时要合理使用接口和抽象类来定义契约，让代码更加灵活。', '深入理解Java面向对象编程的三大特性：封装、继承和多态，掌握核心概念与实践技巧。', 'https://example.com/cover-java-oop.jpg', 1, 1, 128, 78, 35, 15, 12, 48, 36, 20, 12, 35, 8, '2026-05-13 10:00:00', '2026-05-13 10:00:00', '2026-05-20 10:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (13, 'Spring Boot快速搭建RESTful API', '## 为什么选择Spring Boot？\n\nSpring Boot是由Pivotal团队提供的全新框架，其设计目的是用来简化Spring应用的初始搭建以及开发过程。它通过自动配置、起步依赖和监控端点等特性，让开发者能够专注于业务逻辑的实现。\n\n### 创建项目\n\n最简单的方式是通过Spring Initializr来创建一个新的Spring Boot项目。你需要选择项目的基本信息，比如Group、Artifact，以及需要的依赖。一个典型的Web项目至少需要引入spring-boot-starter-web依赖。\n\n### 构建RESTful API\n\n使用@RestController注解可以很方便地创建RESTful风格的API：\n\n```java\n@RestController\n@RequestMapping("/api/users")\npublic class UserController {\n    @GetMapping("/{id}")\n    public ResponseEntity<User> getUser(@PathVariable Long id) {\n        User user = userService.findById(id);\n        return ResponseEntity.ok(user);\n    }\n\n    @PostMapping\n    public ResponseEntity<User> createUser(@Valid @RequestBody User user) {\n        User created = userService.save(user);\n        return ResponseEntity.status(HttpStatus.CREATED).body(created);\n    }\n}\n```\n\n### 统一返回格式\n\n在实际项目中，通常会封装一个统一的响应格式：\n\n```java\npublic class ApiResponse<T> {\n    private int code;\n    private String message;\n    private T data;\n    // getters and setters...\n}\n```\n\n这样前端就可以根据统一的格式来处理所有接口的返回结果，减少沟通成本。\n\n### 全局异常处理\n\n通过@ControllerAdvice和@ExceptionHandler可以实现全局的异常处理，避免在每个Controller中重复写try-catch。这是构建健壮API的重要一步。\n\nSpring Boot让Java Web开发重新变得简单高效，是现代Java后端开发的首选框架。', 'Spring Boot快速入门指南，从零搭建RESTful API服务，掌握自动配置、全局异常处理等核心功能。', 'https://example.com/cover-springboot.jpg', 1, 1, 256, 145, 82, 29, 22, 98, 76, 38, 22, 67, 15, '2026-05-14 09:00:00', '2026-05-14 09:00:00', '2026-05-20 09:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (14, 'React Hooks完全指南', '## 什么是React Hooks？\n\nReact Hooks是React 16.8版本引入的新特性，它可以让你在不编写class的情况下使用state以及其他的React特性。Hooks的引入彻底改变了React组件的编写方式。\n\n### useState - 状态管理\n\nuseState是最基础的Hook，用于在函数组件中添加局部状态：\n\n```jsx\nimport React, { useState } from "react";\n\nfunction Counter() {\n  const [count, setCount] = useState(0);\n\n  return (\n    <div>\n      <p>点击了 {count} 次</p>\n      <button onClick={() => setCount(count + 1)}>点击</button>\n    </div>\n  );\n}\n```\n\n### useEffect - 副作用处理\n\nuseEffect可以让你在函数组件中执行副作用操作，比如数据获取、订阅或手动修改DOM。它相当于class组件中的componentDidMount、componentDidUpdate和componentWillUnmount的组合。\n\n```jsx\nuseEffect(() => {\n  document.title = `点击了 ${count} 次`;\n  return () => {\n    // 清理逻辑\n  };\n}, [count]); // 依赖数组\n```\n\n### useContext - 上下文共享\n\nuseContext让你可以在组件树中共享数据，而不必通过props一层层传递。配合Context API，可以优雅地实现全局状态管理。\n\n### 自定义Hooks\n\n自定义Hook是复用状态逻辑的最佳方式。你可以把组件中重复的逻辑抽取到一个自定义Hook中，以use开头命名：\n\n```jsx\nfunction useWindowWidth() {\n  const [width, setWidth] = useState(window.innerWidth);\n  useEffect(() => {\n    const handler = () => setWidth(window.innerWidth);\n    window.addEventListener("resize", handler);\n    return () => window.removeEventListener("resize", handler);\n  }, []);\n  return width;\n}\n```\n\nHooks让React代码更加简洁、易于测试和复用，是现代React开发的基础技能。', '全面解析React Hooks的使用方法，包含useState、useEffect、useContext及自定义Hook的实战指南。', 'https://example.com/cover-react.jpg', 2, 1, 189, 102, 65, 22, 18, 75, 55, 28, 13, 48, 12, '2026-05-15 14:30:00', '2026-05-15 14:30:00', '2026-05-20 14:30:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (15, 'MySQL索引优化实战', '## 为什么需要索引优化？\n\n索引是数据库性能优化的核心手段。一个好的索引可以让查询速度提升几个数量级，而一个糟糕的索引则可能拖慢整个系统的性能。理解索引的工作原理和优化策略，是每个后端开发者的必备技能。\n\n### B+树索引原理\n\nMySQL的InnoDB存储引擎使用B+树作为索引的底层数据结构。B+树是一种平衡多路查找树，所有的数据都存储在叶子节点上，非叶子节点只存储键值信息。\n\n这种结构的优势在于：\n1. 树的高度很低，I/O次数少\n2. 叶子节点之间通过链表连接，适合范围查询\n3. 查询效率稳定，每次查询的时间复杂度都是O(log n)\n\n### 索引类型\n\nMySQL支持多种索引类型：\n- **主键索引**（聚簇索引）：数据按照主键顺序物理存储\n- **唯一索引**：确保列值的唯一性\n- **普通索引**：最基本的索引类型，没有唯一性限制\n- **联合索引**：多个列组合成一个索引\n- **全文索引**：用于全文搜索\n\n### 联合索引与最左前缀原则\n\n联合索引遵循"最左前缀"原则。对于索引(a, b, c)，以下查询可以利用索引：\n- WHERE a = 1\n- WHERE a = 1 AND b = 2\n- WHERE a = 1 AND b = 2 AND c = 3\n\n而以下查询无法充分利用索引：\n- WHERE b = 2 （跳过了a）\n- WHERE a = 1 AND c = 3 （b被跳过，c部分无法使用）\n\n### 使用EXPLAIN分析查询\n\nEXPLAIN命令是分析SQL性能的利器。通过它可以看到查询是否使用了索引、扫描了多少行等信息：\n\n```sql\nEXPLAIN SELECT * FROM orders WHERE user_id = 100 AND status = "paid";\n```\n\n重点关注type列，从好到差依次是：system > const > eq_ref > ref > range > index > ALL。\n\n### 索引优化建议\n\n1. 为WHERE、JOIN、ORDER BY涉及的列创建索引\n2. 避免在索引列上使用函数或运算\n3. 联合索引的列顺序很重要，把选择性高的列放在前面\n4. 定期分析和优化表：ANALYZE TABLE和OPTIMIZE TABLE\n5. 不要过度索引，索引会占用磁盘空间并影响写入性能', '深入MySQL索引优化，掌握B+树原理、联合索引最左前缀规则、EXPLAIN分析等核心技能。', 'https://example.com/cover-mysql.jpg', 3, 1, 312, 178, 98, 36, 28, 125, 92, 45, 22, 89, 21, '2026-05-16 11:00:00', '2026-05-16 11:00:00', '2026-05-20 11:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (16, '微服务架构设计最佳实践', '## 什么是微服务架构？\n\n微服务架构是一种将单个应用程序开发为一组小服务的方法，每个服务运行在自己的进程中，并通过轻量级机制（通常是HTTP API或消息队列）进行通信。这些服务围绕业务能力构建，可以通过全自动部署机制独立部署。\n\n### 微服务 vs 单体架构\n\n传统单体架构将所有的业务逻辑打包在一个应用中，随着业务增长，代码库会变得庞大复杂，维护成本急剧上升。微服务将系统拆分为多个独立的服务，每个服务专注于特定的业务领域。\n\n微服务的优势：\n- 独立部署和扩展\n- 技术栈灵活\n- 团队自治\n- 故障隔离\n\n但微服务也带来了分布式系统的复杂性：\n- 网络延迟和容错\n- 分布式事务\n- 服务发现和配置管理\n- 运维复杂度增加\n\n### 服务拆分原则\n\n拆分微服务时应该遵循领域驱动设计（DDD）的思想，按照业务边界来划分服务边界。一个好的服务拆分应该做到高内聚、低耦合。\n\n常见的拆分策略包括：\n1. 按业务能力拆分\n2. 按子域拆分（核心域、支撑域、通用域）\n3. 按团队组织结构拆分（康威定律）\n\n### 服务间通信\n\n同步通信通常使用REST API或gRPC，适合需要即时响应的场景。异步通信使用消息队列（如Kafka、RabbitMQ），适合需要解耦和提高系统弹性的场景。\n\n### 分布式系统挑战\n\n1. **服务发现**：使用Consul、Eureka或Kubernetes Service来实现\n2. **配置管理**：使用Spring Cloud Config或Apollo集中管理\n3. **熔断降级**：使用Hystrix或Sentinel防止级联故障\n4. **链路追踪**：使用SkyWalking或Jaeger实现分布式追踪\n5. **日志聚合**：使用ELK（Elasticsearch + Logstash + Kibana）统一日志\n\n微服务不是银弹。对于小型项目或团队，单体架构可能是更好的选择。架构的选择应该基于实际的业务需求和团队能力。', '微服务架构设计完整指南，涵盖服务拆分原则、通信方式、分布式挑战及最佳实践建议。', 'https://example.com/cover-microservice.jpg', 4, 1, 203, 118, 62, 23, 19, 80, 61, 27, 16, 56, 18, '2026-05-17 08:30:00', '2026-05-17 08:30:00', '2026-05-20 08:30:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (17, 'Redis缓存设计与常见问题', '## Redis的核心数据结构\n\nRedis是一个开源的、基于内存的数据结构存储系统，可以用作数据库、缓存和消息中间件。它支持多种数据结构，包括字符串、哈希、列表、集合和有序集合等。\n\n### String（字符串）\n\nString是Redis中最基本的数据类型，一个Key对应一个Value。String类型是二进制安全的，可以包含任何数据，比如图片或序列化的对象。一个键最大能存储512MB。\n\n常用场景：\n- 缓存对象（存储JSON序列化后的数据）\n- 分布式锁（SET NX + EXPIRE）\n- 计数器（INCR/DECR命令）\n- 限流（基于INCR + EXPIRE实现滑动窗口）\n\n### Hash（哈希）\n\nHash是一个String类型的field和value的映射表，特别适合存储对象。相比将对象序列化为字符串存储，Hash可以方便地修改对象中的某个字段。\n\n```\nHSET user:1001 name "张三" age 25 email "zhangsan@example.com"\nHGET user:1001 name  // 返回 "张三"\n```\n\n### 缓存穿透、击穿和雪崩\n\n**缓存穿透**：查询一个不存在的数据，由于缓存不命中，请求直接打到数据库。解决方案是使用布隆过滤器或将空值也缓存起来。\n\n**缓存击穿**：热点Key过期瞬间，大量并发请求直接打到数据库。解决方案是使用互斥锁或设置热点数据永不过期。\n\n**缓存雪崩**：大量缓存Key在同一时间过期，或Redis服务宕机，导致所有请求打到数据库。解决方案是给过期时间加上随机值，或使用Redis集群保证高可用。\n\n### 缓存一致性\n\nCache Aside Pattern是最常用的缓存模式：\n1. 读操作：先读缓存，缓存未命中则读数据库，然后将结果写入缓存\n2. 写操作：先更新数据库，再删除缓存\n\n删除缓存而不是更新缓存，是因为删除操作更简单，而且可以避免并发更新导致的缓存与数据库不一致问题。\n\n### 持久化策略\n\nRedis支持两种持久化方式：\n- RDB（快照）：在指定时间间隔内将内存中的数据快照写入磁盘\n- AOF（追加文件）：将每个写操作记录到日志文件中\n\n生产环境建议两者结合使用，RDB用于灾难恢复，AOF用于保证数据完整性。', '全面了解Redis缓存设计，掌握五种核心数据结构、缓存三大问题及解决方案、数据一致性策略。', 'https://example.com/cover-redis.jpg', 3, 1, 178, 96, 58, 24, 16, 68, 55, 26, 13, 45, 10, '2026-05-18 15:00:00', '2026-05-18 15:00:00', '2026-05-20 15:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (18, '前端性能优化全攻略', '## 为什么要做前端性能优化？\n\n根据Google的研究，页面加载时间从1秒增加到3秒，用户跳出率增加32%；从1秒增加到5秒，跳出率增加90%。前端性能直接影响用户体验和业务转化率。\n\n### 资源加载优化\n\n**代码分割（Code Splitting）**\n\n使用Webpack、Vite等打包工具的动态导入功能，将代码按路由或组件拆分，实现按需加载：\n\n```javascript\nconst UserProfile = React.lazy(() => import("./UserProfile"));\n```\n\n**图片优化**\n\n- 使用WebP格式，相比JPEG/PNG体积减少25%-35%\n- 响应式图片：使用srcset根据屏幕尺寸加载不同分辨率的图片\n- 懒加载：使用loading="lazy"属性或Intersection Observer API\n- CDN加速：将静态资源部署到CDN节点\n\n**资源压缩**\n\n启用Gzip或Brotli压缩，通常可以节省约70%的带宽。在Nginx中配置很简单：\n\n```nginx\ngzip on;\ngzip_types text/plain text/css application/json application/javascript text/xml;\ngzip_min_length 1000;\n```\n\n### 渲染性能优化\n\n**减少重排和重绘**\n\n- 批量修改DOM：使用DocumentFragment或display: none\n- 使用CSS transform和opacity做动画，它们不会触发重排\n- 使用requestAnimationFrame进行动画操作\n\n**虚拟列表**\n\n当需要渲染大量数据列表时，使用虚拟列表技术（如react-window），只渲染可视区域内的DOM节点，大幅减少DOM操作。\n\n### 缓存策略\n\n合理利用HTTP缓存可以有效减少重复请求：\n- 对不常变化的资源使用强缓存（Cache-Control: max-age）\n- 对需要更新的资源使用协商缓存（ETag / Last-Modified）\n- 使用Service Worker实现离线缓存\n\n### 性能监控\n\n使用Lighthouse、WebPageTest等工具定期进行性能测试。在项目中接入Web Vitals监控（LCP、FID、CLS），及时发现性能问题。核心Web指标：\n- LCP（最大内容绘制） < 2.5秒\n- FID（首次输入延迟） < 100毫秒\n- CLS（累计布局偏移） < 0.1', '前端性能优化完整攻略，从资源加载、渲染优化到缓存策略，全面提升Web应用的用户体验。', 'https://example.com/cover-performance.jpg', 2, 1, 145, 82, 48, 15, 12, 58, 42, 21, 12, 38, 9, '2026-05-19 16:00:00', '2026-05-19 16:00:00', '2026-05-20 16:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (19, '一个程序员的周末日常', '## 周末清晨\n\n闹钟在早上七点拨动，窗外已经有鸟鸣声。我没有像工作日那样匆忙起床，而是躺在床上发了一会儿呆。阳光透过窗帘缝隙洒进来，在地板上画出一道金色的线。\n\n起床后第一件事是烧水泡茶。最近迷上了铁观音，那股淡淡的兰花香总能让人的心安静下来。端着茶杯走到阳台，楼下的小区花园里已经有老人在打太极了。\n\n### 菜市场的烟火气\n\n九点多出门去菜市场。这是我每周最期待的事情之一。菜市场是城市里最有烟火气的地方——卖菜阿姨的吆喝声、鱼贩子刮鱼鳞的唰唰声、买菜大妈讨价还价的热情，一切都充满了生活的质感。\n\n今天买了两斤排骨、一把青菜、几个番茄。卖菜阿姨还多送了我两根葱，笑着说小伙子长得帅，多送你点。这种小小的善意总让人心头一暖。\n\n### 下厨的乐趣\n\n中午做了糖醋排骨和番茄炒蛋。做饭对我来说是一种放松，把食材一步步变成美味的过程，就像写代码时把需求变成功能一样，有一种创造的满足感。\n\n糖醋排骨的秘诀在于糖色要炒到位，酱油和醋的比例要拿捏好。今天的成品色泽红亮，酸甜适中，配上白米饭简直完美。\n\n### 下午时光\n\n下午窝在沙发上看了一部老电影《海上钢琴师》。1900的故事每次看都有不同的感受。或许每个人心里都有一艘船，有些人选择下船去探索世界，有些人选择留在船上守护自己的热爱。\n\n傍晚去健身房跑了个5公里。运动出汗后整个人神清气爽，感觉一周的疲惫都被冲刷干净了。回来的路上买了杯奶茶奖励自己——健身不就是为了吃得理直气壮嘛。\n\n### 写在最后\n\n这样的周末平淡无奇，但正是这些琐碎的日常构成了生活本身。写代码很重要，但别忘了抬头看看窗外，去感受真实世界里的温度和烟火气。生活不在代码里，生活在每一个认真度过的当下。', '记录一个普通程序员的周末——逛菜市场、下厨做饭、看电影、健身，平淡中藏着生活的全部美好。', 'https://example.com/cover-weekend.jpg', 5, 1, 367, 198, 132, 37, 28, 142, 110, 58, 29, 89, 22, '2026-05-10 07:30:00', '2026-05-10 07:30:00', '2026-05-21 18:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (20, '养猫一年教会我的事', '## 遇见小橘\n\n去年五月，在小区楼下第一次遇见它。一只脏兮兮的小橘猫，瘦得皮包骨头，躲在车底下喵喵叫。我蹲下来伸出手，它犹豫了很久，最后还是慢慢靠了过来。那一刻，我的心就被这只小东西俘获了。\n\n带它去宠物医院检查、打疫苗、洗澡。洗干净后的小橘简直判若两猫——橘色的毛发蓬松柔软，琥珀色的眼睛亮晶晶的。从那天起，我成了一个有猫的人。\n\n### 耐心是被磨出来的\n\n养猫第一课：学会耐心。小橘刚到家的时候到处乱尿、半夜跑酷、把数据线当磨牙棒。我曾经半夜三点被它踩醒，气得想把它送回楼下。但它用脑袋蹭我手心的时候，所有脾气都消了。\n\n渐渐地，我开始理解它的行为。乱尿是因为换了新环境紧张，跑酷是因为白天睡太多，咬数据线是因为无聊。给它买了猫抓板和玩具，每天花时间陪它玩，这些问题慢慢就解决了。\n\n这让我反思自己写代码时的状态。遇到Bug就急躁，调试两小时就坐不住。如果能像对待小橘一样对待代码——多些耐心，尝试理解问题背后的原因，也许很多难题都能迎刃而解。\n\n### 活在当下的能力\n\n小橘教会我最重要的事：活在当下。它不会为昨天没吃到罐头而懊悔，也不会为明天要不要打疫苗而焦虑。它只关心此刻——阳光正好，适合打个盹；窗外的鸟叫，值得竖起耳朵；我手里的逗猫棒，必须抓住。\n\n作为人类，我们太容易陷入对过去的纠结和对未来的担忧中。项目延期了怎么办？晋升没通过怎么办？这些焦虑占据了我太多的大脑内存。看着小橘安详地趴在键盘旁边打呼噜，我突然觉得，也许生活本来就该简单一些。\n\n每天下班回家，听到钥匙转动的声音，小橘就会跑到门口迎接我。它不在乎我今天代码写得怎么样，项目有没有上线——它只是单纯地高兴我回来了。这种不带任何条件的陪伴，是一种难以言喻的治愈。\n\n一年过去了，我从养猫小白变成了熟练铲屎官，小橘也从瘦弱的小猫变成了圆滚滚的大橘。它给了我陪伴，教会了我耐心，让我学会了放慢脚步。有时候我觉得，不是我收养了它，而是它选择了我，来教会我这些生活里最重要的事。', '养猫一年的心路历程，一只小橘猫教会我的关于耐心、陪伴和活在当下的生活哲学。', 'https://example.com/cover-cat.jpg', 5, 1, 892, 456, 312, 124, 89, 345, 278, 156, 89, 203, 56, '2026-05-12 10:00:00', '2026-05-12 10:00:00', '2026-05-21 20:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (21, '记忆中的家乡味道', '## 外婆的厨房\n\n小时候最期待的就是过年回外婆家。外婆家在江南一个小镇上，青瓦白墙的老房子，院子里种着一棵桂花树，秋天的时候满院子都是甜丝丝的香气。\n\n外婆的厨房不大，但总是热气腾腾的。灶台上永远炖着一锅汤，案板上永远有揉好的面团。外婆的手很粗糙，但做出来的菜是我吃过最好吃的。\n\n### 那些念念不忘的味道\n\n**红烧肉**：外婆的红烧肉要用五花三层的五花肉，先焯水去腥，再用冰糖炒糖色。火候是关键，小火慢炖两个小时，直到肉皮软糯、肥肉晶莹剔透。每次我都能就着汤汁扒拉两碗饭。\n\n**清明粿**：每年清明节前后，外婆会去田埂上采艾草，回来榨汁和糯米粉揉成绿色的面团，包上芝麻糖或者笋干肉末的馅。蒸熟后满屋都是艾草的清香，咬一口软糯Q弹。\n\n**腌笃鲜**：春笋上市的季节，外婆会用咸肉、鲜肉和春笋一起炖，汤色乳白，鲜得掉眉毛。这道菜的名字据说来源于炖的时候锅里笃笃笃的声音。\n\n### 味道背后的故事\n\n长大后才明白，让我念念不忘的不只是那些菜的味道，更是那个回不去的时光。外婆在灶台前忙碌的背影，院子里桂花的香气，一家人围坐在八仙桌边吃饭的热闹——这些才是记忆真正的味道。\n\n去年外婆走了，厨房里的灶台再也不会冒热气了。我试着复刻过几次她的红烧肉，用料、步骤都一模一样，但总觉得少了点什么。也许少了的那一味，是爱吧。\n\n如今我在大城市里工作，吃过很多高级餐厅，但再也没有吃到过比外婆做的更好吃的菜。那些味道已经刻进了我的味觉记忆里，成了我这辈子最珍贵的念想。\n\n如果你还能吃到家人做的饭，请一定好好珍惜。因为总有一天你会发现，那个味道，是任何米其林餐厅都给不了的。', '回忆外婆的厨房和那些念念不忘的家常味道——红烧肉、清明粿、腌笃鲜，以及味道背后的亲情与时光。', 'https://example.com/cover-hometown.jpg', 5, 1, 534, 287, 189, 58, 45, 198, 167, 92, 45, 112, 34, '2026-05-14 08:30:00', '2026-05-14 08:30:00', '2026-05-22 09:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (22, '烟雨西湖——春日杭州行记', '## 初见西湖\n\n都说晴西湖不如雨西湖，雨西湖不如雾西湖。我到杭州那天，恰好下着蒙蒙细雨，整座城市笼罩在一层薄纱般的雨雾中。放下行李就直奔西湖，怕错过这难得的烟雨。\n\n站在断桥上看过去，湖面烟波浩渺，远山如黛，几只游船在雨中若隐若现。柳枝被雨水洗得翠绿欲滴，垂在水面上画出涟漪。那一刻脑海里只剩下苏轼的那句——欲把西湖比西子，淡妆浓抹总相宜。\n\n### 环湖漫步\n\n从断桥出发，沿着白堤往孤山方向走。雨天人少，整条堤岸都是我的。路边的樱花已经谢了，但桃花开得正好，粉粉嫩嫩地在雨中摇曳。\n\n经过平湖秋月，在亭子里躲了一会儿雨，看着湖对岸的雷峰塔在水雾中朦朦胧胧。有老人坐在亭子里拉二胡，曲调婉转悠长，和雨声交织在一起，说不出的江南韵味。\n\n走到苏堤时雨渐渐停了，天空露出一点亮光。苏堤两岸种满了柳树和桃树，春天里红绿相间，美得像一幅工笔画。路边有卖藕粉和葱包烩的小摊，买了一份边走边吃，热乎乎的甜食驱散了雨天的湿冷。\n\n### 灵隐禅意\n\n第二天去了灵隐寺。寺庙藏在飞来峰的山林之间，一踏进山门就能闻到檀香的味道。大雄宝殿前的香炉青烟袅袅，善男信女们虔诚地跪拜祈福。\n\n飞来峰的石窟造像很震撼，从五代到元朝的佛像雕刻在崖壁上，经历了千年的风雨，有些已经风化模糊，但依然能感受到古人的虔诚和匠心。\n\n在山腰的茶室里喝了一杯龙井。明前龙井果然名不虚传，茶汤嫩绿清澈，入口甘醇，有股豆花香。窗外是层层叠叠的茶园，茶农们戴着斗笠在采茶，一派田园风光。\n\n### 告别\n\n离开杭州的那个早晨又下起了小雨。坐在去火车站的出租车上，看着窗外被雨水冲刷得干干净净的街道，心里有些不舍。\n\n杭州的美不是那种让人震撼的美，而是一种润物细无声的美。它藏在西湖边的一棵柳树下，藏在灵隐寺的一缕香烟里，藏在一杯龙井的回甘里，藏在雨巷深处的一声二胡里。这座城市，值得一来再来。', '春日杭州游记——烟雨中的西湖、灵隐寺的禅意、一杯龙井的清香，领略江南水乡的温柔与韵味。', 'https://example.com/cover-hangzhou.jpg', 6, 1, 687, 356, 234, 97, 68, 267, 198, 112, 67, 176, 48, '2026-05-15 09:00:00', '2026-05-15 09:00:00', '2026-05-23 10:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (23, '川西自驾：从成都到稻城亚丁', '## 出发\n\n我偷偷地告诉你，有一个地方叫做稻城，我要和我最心爱的人一起去那里，看蔚蓝的天空，看白色的雪山，看金色的草地，看一场秋天的童话。——《从你的全世界路过》\n\n因为这句话，我和两个朋友踏上了川西自驾之旅。从成都出发，经雅安、康定、新都桥，一路向西，目的地是稻城亚丁。\n\n### 折多山：川藏第一关\n\n翻越折多山是行程的第一个考验。海拔4298米的垭口，云雾就在头顶翻涌，经幡在风中猎猎作响。站在垭口往西看，连绵的雪山在阳光下闪闪发光。第一次见到雪山的兴奋让人忘记了高原反应的头疼。\n\n下山时遇到了牦牛群，慢悠悠地走在公路上，完全不把汽车放在眼里。我们只能跟在后面慢慢开，倒也趁机好好看了看路边的风景——草甸上开满了不知名的野花，紫色、黄色、白色点缀在绿毯上。\n\n### 新都桥：摄影家的天堂\n\n傍晚到达新都桥，这里被称为摄影家的天堂。秋天的杨树林一片金黄，藏式民居散落在河谷边，炊烟袅袅升起，远处的雪山作为背景——随手一拍都是壁纸级别的照片。\n\n晚上住在藏民开的民宿里，喝了酥油茶，吃了糌粑。酥油茶咸咸的、奶香浓郁，第一口不太习惯，但越喝越觉得香。老板是个五十多岁的藏族大叔，给我们讲了很多关于藏区文化和转山的故事。\n\n### 稻城亚丁：蓝色星球上最后一片净土\n\n经过两天的车程，终于到达稻城亚丁。景区入口在冲古寺，从这里开始只能徒步或骑马。我们选择了徒步——毕竟都来到这儿了，必须用双脚去丈量这片净土。\n\n沿着栈道走了大约两个小时，牛奶海出现在眼前。那是一种我从未见过的蓝色——不是天空的蓝，也不是大海的蓝，而是一种近乎透明的翠蓝色，像一块巨大的翡翠镶嵌在雪山之间。湖边是白色的沙滩，远处是央迈勇雪山终年不化的冰川。\n\n站在牛奶海边，所有人都沉默了。不是没话说，而是觉得任何语言在这样的大自然面前都显得苍白。那一刻我第一次体会到什么叫敬畏自然。\n\n### 归途\n\n返程走的是川藏南线，经过理塘、雅江。理塘被称为世界高城，海拔4000多米，是仓央嘉措的故乡。在理塘停留了半天，去了长青春科尔寺，转了一圈世界上最大的转经筒。\n\n七天两千里，川西给了我们一场难以忘怀的风景盛宴。但最美的不是某个具体的景点，而是一直在路上——那种自由自在、天大地大的感觉。如果你也喜欢自驾和风景，川西一定不会让你失望。', '成都出发自驾川西大环线，翻越折多山、行摄新都桥、抵达稻城亚丁，一场关于雪山、草甸和自由的旅程。', 'https://example.com/cover-chuanxi.jpg', 6, 1, 1123, 598, 387, 156, 112, 445, 334, 189, 112, 289, 78, '2026-05-17 06:00:00', '2026-05-17 06:00:00', '2026-05-24 08:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (24, '黄山两日：云海日出与迎客松', '## 上山\n\n徐霞客说：五岳归来不看山，黄山归来不看岳。冲着这句话，我在深秋的一个周末去了黄山。\n\n从汤口坐景区大巴到云谷寺，然后坐索道上山。缆车穿过云雾，四周白茫茫一片，什么都看不见。正在失望之际，缆车突然冲出云层——脚下是翻滚的云海，头顶是湛蓝的天空，远处的山峰在云海中露出尖顶，像海中的仙岛。全车厢的人都发出了惊呼。\n\n### 西海大峡谷\n\n西海大峡谷是黄山最惊险的一段。栈道挂在悬崖峭壁上，窄的地方只能容一人通过。往下看是万丈深渊，云海在谷底翻涌。有恐高的朋友走了一半就退回去了，但我坚持走完了全程——因为每一步的风景都不一样。\n\n峡谷里的怪石形态各异，有的像猴子观海，有的像仙人下棋。黄山以奇石著称，这些花岗岩经过亿万年的风化，被大自然雕琢成了各种奇特的造型。\n\n### 日出\n\n为了看日出，凌晨四点就起床了。摸着黑走到光明顶（不是明教那个），山顶上已经聚集了好多人。大家都裹着羽绒服在寒风中瑟瑟发抖，但都目不转睛地盯着东方。\n\n天空从深蓝色逐渐变成浅紫，然后天边出现一道橙红色的光。太阳像一颗火球慢慢从云海中升起，金光照亮了整片天空和云海。人群爆发出欢呼声和掌声。那一刻，早起的困倦、山上的寒冷，全都值了。\n\n### 迎客松\n\n从光明顶往下走，经过飞来石、排云亭，最后到达玉屏楼。那棵著名的迎客松就长在玉屏楼旁边的悬崖上，一棵松树斜伸出一根长长的枝干，姿态就像在欢迎远道而来的客人。\n\n这棵松树已经有800多年的树龄了。看着它扎根在悬崖绝壁上，历经风雨雷电依然挺拔苍翠，不由得心生敬意。它早已不仅仅是一棵树，更是黄山精神的象征。\n\n### 下山\n\n选择步行下山，沿着前山的石阶一路往下。下山虽然不喘，但对膝盖是巨大的考验。路上碰到几个挑山工，挑着沉重的物资上山，汗流浃背但步履稳健。和他们聊了几句，一个大哥笑着说每天要上下山两趟，已经干了二十年了。\n\n回到山脚下，腿已经不听使唤了，但心里满满的。黄山的云海、日出、奇松、怪石，每一样都让人难忘。徐霞客说得没错——看过黄山的山，其他的山真的就成了将就。\n\n如果你也想去黄山，建议在山顶住一晚，日出绝对不容错过。另外记得带登山杖，你的膝盖会感谢你的。', '黄山两日游记——穿越西海大峡谷的险峻、守候光明顶的日出、致敬千年迎客松的坚韧。', 'https://example.com/cover-huangshan.jpg', 6, 1, 567, 298, 189, 88, 56, 223, 167, 94, 56, 145, 42, '2026-05-19 07:00:00', '2026-05-19 07:00:00', '2026-05-24 12:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (25, '从零开始学写作——我的三年写作心得', '## 为什么开始写作？\n\n三年前，我还是一个连200字周报都要憋半天的程序员。那时候觉得写作是文科生的事，和我一个写代码的没什么关系。直到有一次需要写技术方案文档，我对着空白文档发了两个小时的呆，最后交了一篇逻辑混乱、表达不清的东西。\n\n被领导委婉地批评后，我决定认真学写作。没想到这一写就是三年，过程中收获了远超预期的成长。\n\n### 第一阶段：突破不敢写的心理障碍\n\n刚开始写作最大的困难不是写不好，而是不敢写。每写一句话都觉得不够好，写了删、删了写，一个小时过去文档还是空的。\n\n后来我给自己定了一条铁律：先完成，再完美。第一稿的唯一目标就是把想法倒出来，不管用词是否优美、逻辑是否通畅。写完再回过头来修改。这个方法让我终于迈出了第一步。\n\n第一篇文章发表在技术社区上，只收获了3个阅读和0个评论。说不失落是假的，但我告诉自己：每个高手都是从零开始的。\n\n### 第二阶段：学会结构化表达\n\n写了一段时间后，问题从写不出来变成了写不清楚。我发现自己的文章像一盘散沙，观点不清晰，逻辑跳跃，读者看完不知道我想说什么。\n\n于是开始学习结构化表达。最有效的方法是金字塔原理：\n1. 结论先行：每个章节开头先亮出核心观点\n2. 以上统下：上层观点统领下层论据\n3. 归类分组：将相关内容组织在一起\n4. 逻辑递进：按照时间、空间或重要性排列\n\n用这个框架去组织文章，表达立刻清晰了很多。读者的反馈也从看不懂变成了讲得清楚。\n\n### 第三阶段：找到自己的声音\n\n结构和技巧掌握之后，下一步是找到自己的风格。我尝试过模仿很多大V的写法——有的幽默、有的犀利、有的温暖。但模仿来的东西总感觉别扭。\n\n后来发现，最好的风格就是真诚地做自己。我是一个程序员，我对技术的理解、对生活的观察、对成长的思考，这些都是独一无二的。不需要刻意搞笑、不需要强行煽情，只要用心把想说的话说清楚、说真诚，读者是能感受到的。\n\n### 写作带给我的\n\n三年写作给我带来的收获远超预期：\n- 思考更深入：写作是思考的外化，把一个观点写清楚的过程，就是把它想透的过程\n- 表达更清晰：现在写技术方案、做汇报、甚至日常沟通都更有条理了\n- 影响力扩大：通过技术博客，我收到过几次不错的职业机会\n- 认识了新朋友：因为写作，认识了很多志同道合的笔友和读者\n\n如果你也想开始写作，我的建议是：今天就开始，就写300字。不要等准备好了再动笔——你永远不会有准备好的那一天。先写起来，在写的过程中慢慢变好。', '三年写作之路的真诚分享，从写不出200字到拥有自己的声音，关于写作方法、心态转变和意外收获。', 'https://example.com/cover-writing.jpg', 7, 1, 434, 223, 145, 56, 38, 167, 132, 78, 38, 98, 28, '2026-05-20 12:00:00', '2026-05-20 12:00:00', '2026-05-24 15:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (26, '如何利用下班时间提升自己', '## 时间都去哪了？\n\n在IT行业工作五年，见过太多同事白天应付业务需求，晚上刷短视频到深夜，一年下来技术上没有任何成长，然后焦虑、跳槽、继续焦虑。\n\n我自己也经历过这样的阶段。直到两年前，我认真算了一笔账：每天下班后从7点到12点有5个小时，去掉吃饭洗漱1小时，还有4小时。周末两天假设每天有效时间6小时。一周的可自由支配时间大约是4乘5加6乘2等于32小时。\n\n32小时，相当于一份全职工作时间的八成。这些时间用在哪里，很大程度上决定了你五年后会成为什么样的人。\n\n### 建立自己的学习系统\n\n光有决心是不够的，你需要一个可持续的学习系统：\n\n1. 定一个北极星目标\n\n不是我要学好技术这种模糊目标，而是具体的、可衡量的。比如六个月内成为团队里Go语言的首选人或者今年用Rust写一个操作系统内核。目标越具体，行动越清晰。\n\n2. 拆解为可执行的周计划\n\n把大目标拆成每周可以完成的小任务。比如学Go语言，可以拆成：\n- 第1周：基础语法加写一个CLI工具\n- 第2周：并发编程加写一个HTTP Server\n- 第3周：标准库深入加阅读一个开源项目的源码\n\n3. 固定学习时间和环境\n\n我选择每天早上6点到8点学习。原因很简单：这个时间段没有人打扰，大脑最清醒。晚上下班后状态不好，容易放弃。找到适合你的节奏并坚持下去。\n\n4. 输出倒逼输入\n\n被动地看书看视频效果很差。我要求自己每周写一篇博客或做一个demo项目。为了写出有质量的东西，就必须真正学懂、动手实践。这个过程非常痛苦但成长最快。\n\n### 学会休息\n\n很多人以为努力就是拼命。但长期高强度运转只会导致崩溃和放弃。\n\n我的节奏是：\n- 工作日每天专注学习2-3小时\n- 周六全天学习或做项目（6-8小时）\n- 周日完全放松——运动、见朋友、看电影，彻底清空大脑\n\n每周至少留一天完全不碰工作和学习。这不是偷懒，而是为了让其他六天更高效。\n\n### 关于焦虑\n\n学习过程中难免焦虑，特别是看到同龄人升职加薪或者网上各种年薪百万的帖子时。\n\n后来想明白了一个道理：人生是马拉松，不是百米冲刺。你看到的是别人现在的光鲜，看不到的是他们在背后默默付出了多少年。与其把精力用在焦虑上，不如把它们用在行动上。每天进步百分之一，一年后你会是现在的37倍——这就是复利的力量。\n\n种一棵树最好的时间是十年前，其次是现在。无论你已经工作了多少年，只要开始，就不算晚。', '下班后如何有效利用时间进行自我提升？分享我的学习系统、时间管理方法和对抗焦虑的心得。', 'https://example.com/cover-growth.jpg', 7, 1, 678, 387, 223, 102, 67, 289, 198, 102, 56, 156, 45, '2026-05-22 18:00:00', '2026-05-22 18:00:00', '2026-05-25 09:00:00');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (27, 'Spring Boot 微服务架构实战指南', '<h2>一、微服务架构概述</h2><p>微服务架构是一种将单一应用程序划分成一组小服务的架构风格，每个服务运行在自己的进程中，服务间通过轻量级通信机制互相协作。</p><h2>二、Spring Boot优势</h2><p>Spring Boot让Spring应用的开发变得更简单，它提供了<strong>自动配置</strong>、起步依赖和Actuator等特性，大大减少了配置文件的数量。</p><h3>2.1 自动配置原理</h3><p>Spring Boot通过@EnableAutoConfiguration注解和spring.factories文件来实现自动配置，它会根据classpath中的jar包自动配置Spring应用。</p><h2>三、服务注册与发现</h2><p>使用Eureka或Nacos作为注册中心，每个微服务启动时向注册中心注册自己的信息，消费者从注册中心获取服务列表。</p><blockquote>微服务不是银弹，小项目不要滥用。单体应用在大多数场景下已经足够了。</blockquote><h2>四、总结</h2><p>Spring Boot + Spring Cloud是Java生态中最成熟的微服务解决方案，值得深入学习和实践。</p>', '从零开始构建基于Spring Boot的微服务架构，涵盖服务注册、配置中心、网关等核心组件。', '', 11, 1, 2708, 1354, 947, 407, 135, 947, 947, 541, 135, 168, 18, '2026-04-03 19:46:05', '2026-04-03 19:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (28, 'Java并发编程：从synchronized到AQS', '<h2>一、为什么需要并发编程</h2><p>在多核CPU时代，充分利用处理器资源是提升应用性能的关键。Java从诞生之初就内置了对多线程的支持。</p><h2>二、synchronized关键字</h2><p>synchronized是Java中最基本的同步机制，它可以修饰<strong>方法</strong>和<strong>代码块</strong>。底层通过对象的Monitor锁来实现。</p><pre><code>public synchronized void method() {\n    // 临界区代码\n}</code></pre><h2>三、Lock接口与ReentrantLock</h2><p>相比于synchronized，Lock接口提供了更灵活的锁操作，包括<em>可中断的获取锁</em>、<em>超时获取锁</em>和<em>非阻塞获取锁</em>。</p><h2>四、AQS框架</h2><p>AQS（AbstractQueuedSynchronizer）是JUC并发包的核心，它维护了一个<strong>FIFO等待队列</strong>和一个<strong>volatile int state</strong>。</p><p>ReentrantLock、Semaphore、CountDownLatch等工具类都是基于AQS实现的。</p>', '深入理解Java并发编程的核心机制，从最基本的synchronized关键字到复杂的AbstractQueuedSynchronizer框架。', '', 11, 1, 4697, 2348, 1643, 706, 234, 1643, 1643, 939, 234, 230, 7, '2026-04-10 14:46:05', '2026-04-10 14:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (29, '我的2024年度阅读总结', '<h2>📚 年度阅读数据</h2><p>2024年一共读了<strong>42本书</strong>，其中文学类15本、科技类10本、历史类8本、个人成长类9本。</p><h2>🏆 年度Top 5推荐</h2><ol><li><strong>《人类简史》</strong> - 尤瓦尔·赫拉利。重新认识人类文明的发展历程，视角宏大而深刻。</li><li><strong>《原则》</strong> - 瑞·达利欧。桥水基金创始人的生活和工作原则，值得反复阅读。</li><li><strong>《三体》</strong> - 刘慈欣。中国科幻的巅峰之作，想象力令人震撼。</li><li><strong>《代码整洁之道》</strong> - Robert C. Martin。每个程序员都应该读的经典。</li><li><strong>《百年孤独》</strong> - 马尔克斯。魔幻现实主义的巅峰，读完久久不能平静。</li></ol><p>新的一年希望能读到更多好书，与大家共勉！</p>', '回顾过去一年读过的42本书，分享其中最值得推荐的10本，涵盖文学、科技、历史和个人成长。', '', 13, 1, 3707, 1853, 1297, 557, 185, 1297, 1297, 741, 185, 200, 17, '2026-04-17 09:46:05', '2026-04-17 09:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (30, '前端性能优化：从30秒到3秒的蜕变', '<h2>📊 优化前的现状</h2><p>我们的后台管理系统首页加载时间高达<strong>30秒</strong>，用户怨声载道。通过Chrome DevTools分析，主要问题如下：</p><ul><li>JS bundle过大（5.2MB未压缩）</li><li>图片未压缩，单张2MB以上</li><li>没有使用CDN</li><li>接口响应时间超过3秒</li></ul><h2>🔧 优化措施</h2><h3>1. 代码拆分（Code Splitting）</h3><p>使用React.lazy和Suspense实现路由级别的代码拆分，首次加载只加载当前页面所需的代码。</p><h3>2. 图片优化</h3><p>将所有图片转换为WebP格式，并使用srcset实现响应式图片。图片体积减少了<strong>70%</strong>。</p><h2>📈 优化结果</h2><p>经过一系列优化，首页加载时间从30秒降到了<strong>3秒</strong>，用户满意度显著提升。</p>', '记录一次真实项目的前端性能优化经历，分享缓存策略、代码拆分、图片优化等实战经验。', '', 11, 1, 3735, 1867, 1307, 561, 186, 1307, 1307, 747, 186, 284, 20, '2026-04-24 04:46:05', '2026-04-24 04:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (31, '周末烘焙日记：抹茶千层蛋糕', '<h2>🥞 准备材料</h2><ul><li>低筋面粉 200g</li><li>抹茶粉 15g</li><li>鸡蛋 4个</li><li>牛奶 500ml</li><li>淡奶油 400ml</li><li>细砂糖 80g</li></ul><h2>👩‍🍳 制作步骤</h2><ol><li>将面粉和抹茶粉过筛混合</li><li>鸡蛋打散后加入牛奶搅拌均匀</li><li>分次加入粉类，搅拌至无颗粒</li><li><strong>关键步骤：</strong>面糊要过筛3次以上，才会有细腻的口感</li><li>中小火煎制薄饼皮，每面约30秒</li><li>淡奶油加糖打发至7成</li><li>一层饼皮一层奶油叠加，放入冰箱冷藏4小时</li></ol><p>虽然第一次做形状不够完美，但味道真的很棒！<em>抹茶的微苦配上奶油的甜，简直是绝配。</em></p>', '第一次尝试制作抹茶千层蛋糕，虽然过程有些曲折，但结果令人惊喜！', '', 12, 1, 5029, 2514, 1760, 755, 251, 1760, 1760, 1005, 251, 280, 27, '2026-04-30 23:46:05', '2026-04-30 23:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (32, '深入理解MySQL索引原理', '<h2>一、索引是什么</h2><p>索引是帮助MySQL<strong>高效获取数据</strong>的<strong>排好序的数据结构</strong>。最常见的是B+树索引。</p><h2>二、B+树的特点</h2><ul><li>所有数据都存储在叶子节点</li><li>非叶子节点只存储索引键</li><li>叶子节点之间通过指针连接，支持范围查询</li></ul><h2>三、聚集索引 vs 非聚集索引</h2><p>InnoDB的主键索引是<strong>聚集索引</strong>，数据直接存储在叶子节点。而二级索引的叶子节点存储的是主键值。</p><h2>四、索引优化实战</h2><p>以下SQL如何使用索引？</p><pre><code>SELECT * FROM user \nWHERE age > 18 \nORDER BY create_time DESC \nLIMIT 10;</code></pre><p>建议创建(age, create_time)联合索引，利用索引下推优化。</p>', '从B+树数据结构开始，彻底搞懂MySQL索引的底层原理和优化策略。', '', 11, 1, 3839, 1919, 1343, 577, 191, 1343, 1343, 767, 191, 291, 9, '2026-05-07 18:46:05', '2026-05-07 18:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (33, '丽江旅行记：一个人的慢时光', '<h2>✈️ 出发</h2><p>订了一张去丽江的机票，没有做太多攻略，就是想<strong>放空自己</strong>。工作三年了，第一次请了这么长的假。</p><h2>🏘️ 古城漫步</h2><p>丽江古城比我想象中要安静很多。清晨的古城最美，石板路上只有零星的行人，阳光斜斜地洒在木质建筑上，空气里弥漫着淡淡的花香。</p><p>找了一家小咖啡馆，坐在二楼临窗的位置，看着下面的人来人往，<em>时间仿佛变得很慢很慢。</em></p><h2>🏔️ 玉龙雪山</h2><p>海拔4680米，虽然没有高原反应，但爬最后一段台阶时还是气喘吁吁。当站在观景台上看到白雪覆盖的山峰时，<strong>一切疲惫都值得了。</strong></p><p>这次旅行最大的收获是：<strong>学会了一个人独处，也学会了不给自己设限。</strong></p>', '独自踏上丽江之旅，在古城的小巷里迷失，在雪山下感受自然的壮美。', '', 12, 1, 5141, 2570, 1799, 772, 257, 1799, 1799, 1028, 257, 270, 23, '2026-05-14 13:46:05', '2026-05-14 13:46:05', '2026-06-02 19:46:05');
INSERT INTO `article` (`id`, `title`, `content`, `summary`, `cover_image`, `category_id`, `status`, `view_count`, `male_view_count`, `female_view_count`, `unknown_view_count`, `age_under_18`, `age_18_25`, `age_26_35`, `age_36_45`, `age_above_45`, `like_count`, `comment_count`, `publish_time`, `create_time`, `update_time`) VALUES (34, 'Python vs Java：一个全栈开发者的视角', '<h2>🔍 语言定位</h2><p><strong>Java</strong>：编译型语言，强类型，适合大型企业级项目。<strong>Python</strong>：解释型语言，动态类型，适合快速开发和数据分析。</p><h2>⚡ 开发效率对比</h2><p>同样的功能，Python代码量通常是Java的<strong>1/3到1/5</strong>。但Java的IDE支持（IntelliJ IDEA）远超Python。</p><h2>🏗️ 项目适用场景</h2><table><tr><th>场景</th><th>推荐语言</th></tr><tr><td>大型企业后端系统</td><td>Java</td></tr><tr><td>数据分析和AI</td><td>Python</td></tr><tr><td>快速原型开发</td><td>Python</td></tr><tr><td>安卓开发</td><td>Java/Kotlin</td></tr></table><h2>💡 我的建议</h2><p>不要纠结语言之争。<strong>语言只是工具</strong>，选择合适的工具解决问题才是工程师的核心能力。</p>', '作为同时使用Python和Java的开发者，分享两种语言在实际项目中的优劣和适用场景。', '', 11, 1, 4599, 2299, 1609, 691, 229, 1609, 1609, 919, 229, 252, 26, '2026-05-21 08:46:05', '2026-05-21 08:46:05', '2026-06-02 19:46:05');
